import{_ as n,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Automatische Kontextinjektion: Agenten-Vorgewitter | opencode-supermemory","description":"Lernen Sie den automatischen Kontextinjektionsmechanismus von opencode-supermemory kennen. Erfahren Sie, wie der Agent beim Sitzungsstart Benutzerprofil und Projektwissen erhält.","frontmatter":{"title":"Automatische Kontextinjektion: Agenten-Vorgewitter | opencode-supermemory","sidebarTitle":"Kontextinjektion","subtitle":"Automatische Kontextinjektion: Agenten-Vorgewitter","description":"Lernen Sie den automatischen Kontextinjektionsmechanismus von opencode-supermemory kennen. Erfahren Sie, wie der Agent beim Sitzungsstart Benutzerprofil und Projektwissen erhält.","tags":["context","injection","prompt","memory"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"de/supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"de/supermemoryai/opencode-supermemory/core/context-injection/index.md"}'),r={name:"de/supermemoryai/opencode-supermemory/core/context-injection/index.md"};function a(o,e,l,d,h,u){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="automatische-kontextinjektionsmechanismus-lassen-sie-den-agenten-vorhersehen" tabindex="-1">Automatische Kontextinjektionsmechanismus: Lassen Sie den Agenten &quot;vorhersehen&quot; <a class="header-anchor" href="#automatische-kontextinjektionsmechanismus-lassen-sie-den-agenten-vorhersehen" aria-label="Permalink to &quot;Automatische Kontextinjektionsmechanismus: Lassen Sie den Agenten &quot;vorhersehen&quot;&quot;">​</a></h1><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><p>Nach dieser Lektion können Sie:</p><ol><li><strong>Verstehen</strong>, warum der Agent sofort Ihre Codierungsgewohnheiten und die Projektarchitektur kennt.</li><li><strong>Meistern</strong> das &quot;dreidimensionale Modell&quot; der Kontextinjektion (Benutzerprofil, Projektwissen, relevante Speicher).</li><li><strong>Lernen</strong>, Schlüsselwörter (z. B. &quot;Remember this&quot;) zu verwenden, um das Speicherverhalten des Agenten aktiv zu beeinflussen.</li><li><strong>Konfigurieren</strong> die Anzahl der injizierten Einträge, um die Kontextlänge mit Informationsreichtum auszugleichen.</li></ol><hr><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Bevor es ein Speicher-Plugin gab, war der Agent bei jeder neuen Sitzung ein leeres Blatt. Sie mussten ihm immer wieder sagen: &quot;Ich verwende TypeScript&quot;, &quot;Dieses Projekt verwendet Next.js&quot;.</p><p><strong>Kontextinjektion (Context Injection)</strong> löst dieses Problem. Es ist so, als ob Sie dem Agenten im Moment des Erwachens eine &quot;Aufgabenübersicht&quot; in den Kopf stecken.</p><h3 id="auslosezeitpunkt" tabindex="-1">Auslösezeitpunkt <a class="header-anchor" href="#auslosezeitpunkt" aria-label="Permalink to &quot;Auslösezeitpunkt&quot;">​</a></h3><p>opencode-supermemory ist sehr zurückhaltend und wird nur bei <strong>der ersten Nachricht der Sitzung</strong> automatisch ausgelöst.</p><ul><li><strong>Warum bei der ersten Nachricht?</strong> Weil dies der entscheidende Moment ist, um den Ton der Sitzung zu bestimmen.</li><li><strong>Was ist mit nachfolgenden Nachrichten?</strong> Spätere Nachrichten werden nicht mehr automatisch injiziert, um den Dialogfluss nicht zu stören, es sei denn, Sie lösen ihn aktiv aus (siehe unten &quot;Schlüsselwortauslösung&quot;).</li></ul><h3 id="dreidimensionales-injektionsmodell" tabindex="-1">Dreidimensionales Injektionsmodell <a class="header-anchor" href="#dreidimensionales-injektionsmodell" aria-label="Permalink to &quot;Dreidimensionales Injektionsmodell&quot;">​</a></h3><p>Das Plugin ruft parallel drei Arten von Daten ab und kombiniert sie zu einem <code>[SUPERMEMORY]</code>-Prompt-Block:</p><table tabindex="0"><thead><tr><th>Datendimension</th><th>Quelle</th><th>Funktion</th><th>Beispiel</th></tr></thead><tbody><tr><td><strong>1. Benutzerprofil</strong> (Profile)</td><td><code>getProfile</code></td><td>Ihre langfristigen Präferenzen</td><td>&quot;Benutzer bevorzugt funktionale Programmierung&quot;, &quot;bevorzugt Pfeilfunktionen&quot;</td></tr><tr><td><strong>2. Projektwissen</strong> (Project)</td><td><code>listMemories</code></td><td>Globales Wissen über das aktuelle Projekt</td><td>&quot;Dieses Projekt verwendet Clean Architecture&quot;, &quot;API befindet sich in src/api&quot;</td></tr><tr><td><strong>3. Relevante Speicher</strong> (Relevant)</td><td><code>searchMemories</code></td><td>Frühere Erfahrungen, die mit Ihrem ersten Satz relevant sind</td><td>Sie fragen &quot;Wie behebe ich diesen Bug&quot;, es sucht nach früheren ähnlichen Lösungsaufzeichnungen</td></tr></tbody></table><hr><h2 id="was-wird-injiziert" tabindex="-1">Was wird injiziert? <a class="header-anchor" href="#was-wird-injiziert" aria-label="Permalink to &quot;Was wird injiziert?&quot;">​</a></h2><p>Wenn Sie die erste Nachricht in OpenCode senden, fügt das Plugin im Hintergrund stillschweigend den folgenden Inhalt in den System-Prompt ein.</p><details class="details custom-block"><summary>Klicken Sie, um die reale Struktur des injizierten Inhalts anzuzeigen</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>Nachdem der Agent diese Informationen gesehen hat, wird er sich wie ein erfahrener Mitarbeiter verhalten, der schon lange an diesem Projekt gearbeitet hat, und nicht wie ein neuer Praktikant.</p><hr><h2 id="schlusselwortauslosungsmechanismus-nudge" tabindex="-1">Schlüsselwortauslösungsmechanismus (Nudge) <a class="header-anchor" href="#schlusselwortauslosungsmechanismus-nudge" aria-label="Permalink to &quot;Schlüsselwortauslösungsmechanismus (Nudge)&quot;">​</a></h2><p>Neben der automatischen Injektion am Anfang können Sie die Speicherfunktion jederzeit im Dialog &quot;aufwecken&quot;.</p><p>Das Plugin verfügt über einen <strong>Schlüsselwortdetektor</strong>. Solange Ihre Nachricht bestimmte Auslösewörter enthält, sendet das Plugin dem Agenten einen &quot;unsichtbaren Hinweis&quot; (Nudge) und zwingt ihn, das Speichertool aufzurufen.</p><h3 id="standardausloseworter" tabindex="-1">Standardauslösewörter <a class="header-anchor" href="#standardausloseworter" aria-label="Permalink to &quot;Standardauslösewörter&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>... (mehr siehe Quellcodekonfiguration)</li></ul><h3 id="interaktionsbeispiel" tabindex="-1">Interaktionsbeispiel <a class="header-anchor" href="#interaktionsbeispiel" aria-label="Permalink to &quot;Interaktionsbeispiel&quot;">​</a></h3><p><strong>Ihre Eingabe</strong>:</p><blockquote><p>Das API-Antwortformat hat sich geändert, <strong>remember</strong> verwenden Sie künftig <code>data.result</code> statt <code>data.payload</code>.</p></blockquote><p><strong>Plugin erkennt &quot;remember&quot;</strong>:</p><blockquote><p>(Hintergrund injiziert Hinweis): <code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>Agent reagiert</strong>:</p><blockquote><p>Verstanden. Ich werde diese Änderung merken. <em>(Hintergrund ruft <code>supermemory.add</code> auf, um den Speicher zu speichern)</em></p></blockquote><hr><h2 id="tiefenkonfiguration" tabindex="-1">Tiefenkonfiguration <a class="header-anchor" href="#tiefenkonfiguration" aria-label="Permalink to &quot;Tiefenkonfiguration&quot;">​</a></h2><p>Sie können das Injektionsverhalten anpassen, indem Sie <code>~/.config/opencode/supermemory.jsonc</code> ändern.</p><h3 id="haufige-konfigurationsoptionen" tabindex="-1">Häufige Konfigurationsoptionen <a class="header-anchor" href="#haufige-konfigurationsoptionen" aria-label="Permalink to &quot;Häufige Konfigurationsoptionen&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Ob das Benutzerprofil injiziert werden soll (Standard true)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Wie viele Projektspeicher jeweils injiziert werden (Standard 10)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Erhöhen, damit der Agent das Projekt besser kennt, aber verbraucht mehr Token</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Wie viele Benutzerprofileinträge jeweils injiziert werden (Standard 5)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Benutzerdefinierte Auslösewörter (unterstützt Regex)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;记一下&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;永久保存&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Hinweis</p><p>Nach Änderung der Konfiguration müssen Sie OpenCode neu starten oder das Plugin neu laden, damit die Änderungen wirksam werden.</p></div><hr><h2 id="haufige-fragen" tabindex="-1">Häufige Fragen <a class="header-anchor" href="#haufige-fragen" aria-label="Permalink to &quot;Häufige Fragen&quot;">​</a></h2><h3 id="f-nimmt-die-injizierte-information-viele-tokens-ein" tabindex="-1">F: Nimmt die injizierte Information viele Tokens ein? <a class="header-anchor" href="#f-nimmt-die-injizierte-information-viele-tokens-ein" aria-label="Permalink to &quot;F: Nimmt die injizierte Information viele Tokens ein?&quot;">​</a></h3><p><strong>A</strong>: Es nimmt einen Teil ein, ist aber normalerweise kontrollierbar. Mit der Standardkonfiguration (10 Projektspeicher + 5 Profileinträge) verbraucht es etwa 500-1000 Token. Für moderne Large Language Models (wie Claude 3.5 Sonnet) mit 200k Kontext ist dies ein Bruchteil.</p><h3 id="f-warum-reagiert-es-nicht-wenn-ich-remember-sage" tabindex="-1">F: Warum reagiert es nicht, wenn ich &quot;remember&quot; sage? <a class="header-anchor" href="#f-warum-reagiert-es-nicht-wenn-ich-remember-sage" aria-label="Permalink to &quot;F: Warum reagiert es nicht, wenn ich &quot;remember&quot; sage?&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>Überprüfen Sie, ob die Rechtschreibung korrekt ist (unterstützt Regex-Matching).</li><li>Bestätigen Sie, ob der API Key korrekt konfiguriert ist (wenn das Plugin nicht initialisiert ist, wird es nicht ausgelöst).</li><li>Der Agent könnte sich entscheiden, es zu ignorieren (obwohl das Plugin es erzwungen hat, hat der Agent das letzte Wort).</li></ol><h3 id="f-wie-werden-relevante-speicher-gesucht" tabindex="-1">F: Wie werden &quot;relevante Speicher&quot; gesucht? <a class="header-anchor" href="#f-wie-werden-relevante-speicher-gesucht" aria-label="Permalink to &quot;F: Wie werden &quot;relevante Speicher&quot; gesucht?&quot;">​</a></h3><p><strong>A</strong>: Sie werden basierend auf dem Inhalt Ihrer <strong>ersten Nachricht</strong> durch semantische Suche gefunden. Wenn Ihr erster Satz nur &quot;Hi&quot; sagt, werden möglicherweise keine nützlichen relevanten Speicher gefunden, aber &quot;Projektwissen&quot; und &quot;Benutzerprofil&quot; werden weiterhin injiziert.</p><hr><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li><strong>Automatische Injektion</strong> wird nur bei der ersten Nachricht der Sitzung ausgelöst.</li><li><strong>Dreidimensionales Modell</strong> umfasst Benutzerprofil, Projektwissen und relevante Speicher.</li><li><strong>Schlüsselwortauslösung</strong> ermöglicht es Ihnen, den Agenten jederzeit zu befehlen, Speicher zu speichern.</li><li>Durch die <strong>Konfigurationsdatei</strong> können Sie die Menge der injizierten Informationen steuern.</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../tools/">Tool-Suite-Detaillierung: Den Agenten Speichern lehren</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie man <code>add</code>, <code>search</code> und andere Tools manuell verwendet.</li><li>Wie man fehlerhafte Speicher anzeigt und löscht.</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Injektionsauslösungslogik</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>Schlüsselworterkennung</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Standardkonfiguration</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>formatContextForPrompt()</code>: Assembliert den <code>[SUPERMEMORY]</code>-Textblock.</li><li><code>detectMemoryKeyword()</code>: Regex-Matching der Auslösewörter in der Benutzernachricht.</li></ul></details><h2 id="vorschau-auf-die-nachste-lektion-1" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion-1" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../tools/">Tool-Suite-Detaillierung: Den Agenten Speichern lehren</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Meistern Sie 5 Kernmodi des supermemory-Tools: add, search, profile, list, forget</li><li>Wie man manuell in die Speicher des Agenten eingreift und korrigiert</li><li>Speichern mit natürlicher Sprache auslösen</li></ul></blockquote>`,57)])])}const g=n(r,[["render",a]]);export{p as __pageData,g as default};
